with detail = 1 {
    with link = "line.nl.DHA" {
        let da = path("d1.nl.dha");

        with railway = :first :double :cat:dc15 :pax {
            track(:single, da[:den, :sag]);
            track(da[:sag, :her.yh]);
            track(da[:her.yh, :uit.yh]);
            track(da[:uit.yh, :zaa.ye]);
            track(da[:zaa.ye, :zaa]);
            track(:removed, da[:zaa, :awh]);
            track(:nopax, da[:awh, :sin.yr]);
            track(da[:sin.yr, :sin.yz]);
            track(da[:sin.yz, :ams]);
        }
    }
}

